func TestPreClaimIntakeWarnFingerprintEscalatesToOperatorAttention(t *testing.T) {
	inner, _, _ := newExecuteLoopTestStore(t)
	store := &claimCountingStore{Store: inner}

	beadIDs := []string{
		"ddx-intake-warn-1",
		"ddx-intake-warn-2",
		"ddx-intake-warn-3",
		"ddx-intake-warn-4",
		"ddx-intake-warn-5",
	}
	for i, beadID := range beadIDs {
		require.NoError(t, store.Create(&bead.Bead{
			ID:       beadID,
			Title:    "intake warn bead " + beadID,
			Priority: i,
		}))
	}

	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			return ExecuteBeadReport{
				BeadID:    beadID,
				Status:    ExecuteBeadStatusSuccess,
				ResultRev: "rev-" + beadID,
			}, nil
		}),
	}

	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	var eventSink, logBuf bytes.Buffer
	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
	result, err := worker.Run(ctx, rcfg, ExecuteBeadLoopRuntime{
		Log:                         &logBuf,
		EventSink:                   &eventSink,
		NoReview:                    true,
		PreClaimWarnRepeatThreshold: 5,
		PreClaimIntakeHook: func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
			return PreClaimIntakeResult{
				Outcome: PreClaimIntakeError,
				Reason:  "system_unready",
				Detail:  "readiness check unavailable",
			}, nil
		},
	})

	require.NoError(t, err)
	require.NotNil(t, result)
	// The loop should attempt to claim the first 4 beads successfully, then on the 5th
	// it should detect the repeated fingerprint and escalate without claiming.
	assert.Equal(t, 4, result.Attempts, "must attempt the first 4 beads before escalating")
	require.NotNil(t, result.OperatorAttention)
	assert.Equal(t, "preclaim_warn_repeated", result.OperatorAttention.Reason)
	assert.Equal(t, beadIDs[len(beadIDs)-1], result.OperatorAttention.BeadID, "must escalate when processing the 5th bead")
	assert.Equal(t, "operator_attention", result.ExitReason)
	assert.Equal(t, "OperatorAttention", result.StopCondition)

	// Verify the first 4 beads are closed
	for i, beadID := range beadIDs[:4] {
		got, err := store.Get(beadID)
		require.NoError(t, err)
		assert.Equal(t, bead.StatusClosed, got.Status, "bead %d (%s) must be closed after successful execution", i, beadID)
	}

	// Verify the 5th bead remains open
	lastBead, err := store.Get(beadIDs[4])
	require.NoError(t, err)
	assert.Equal(t, bead.StatusOpen, lastBead.Status, "the 5th bead must remain open when escalation triggers")

	// Verify the loop.operator_attention event was emitted with the correct structure
	lines := strings.Split(strings.TrimSpace(eventSink.String()), "\n")
	var escalations []map[string]any
	for _, line := range lines {
		if strings.TrimSpace(line) == "" {
			continue
		}
		var entry map[string]any
		require.NoError(t, json.Unmarshal([]byte(line), &entry))
		if entry["type"] != "loop.operator_attention" {
			continue
		}
		data, ok := entry["data"].(map[string]any)
		require.True(t, ok)
		if data["reason"] == "preclaim_warn_repeated" {
			escalations = append(escalations, data)
		}
	}
	require.Len(t, escalations, 1, "exactly one preclaim_warn_repeated escalation must be emitted")
	esc := escalations[0]
	assert.NotEmpty(t, esc["fingerprint"], "escalation must include the fingerprint")
	assert.Equal(t, float64(5), esc["count"], "escalation count must equal the threshold")
	distinctIDs, ok := esc["distinct_bead_ids"].([]any)
	require.True(t, ok, "distinct_bead_ids must be a JSON array")
	assert.Len(t, distinctIDs, 5, "must track all 5 distinct bead IDs")
	assert.Equal(t, "readiness check unavailable", esc["example_detail"], "must include example detail from the intake hook")

	// Verify the operator_attention event was recorded in the bead's event log
	lastEvents, err := store.Events(beadIDs[4])
	require.NoError(t, err)
	var operatorAttentionEvent *bead.BeadEvent
	for i := range lastEvents {
		if lastEvents[i].Kind == "operator_attention" && lastEvents[i].Summary == "preclaim_warn_repeated" {
			operatorAttentionEvent = &lastEvents[i]
			break
		}
	}
	require.NotNil(t, operatorAttentionEvent, "must record a durable operator_attention event on the bead")
	var body map[string]any
	require.NoError(t, json.Unmarshal([]byte(operatorAttentionEvent.Body), &body))
	assert.Equal(t, "preclaim_warn_repeated", body["reason"])
	assert.Equal(t, float64(5), body["count"])
	assert.NotEmpty(t, body["fingerprint"])
}

